module rol_32bit(A, shift_amount, Y);
    input [31:0] A;
    input [4:0] shift_amount;
    output [31:0] Y;

  wire temp1_(A << shift_amount) = (A << shift_amount);
  wire temp2_(A >> (32 - shift_amount)) = (A >> (32 - shift_amount));
  assign Y = temp1_(A << shift_amount) | temp2_(A >> (32 - shift_amount));
endmodule
